// Limpia el output del agente IA
// Elimina markdown code fences si GPT los incluye
const output = $input.item.json.output || '';
let html = output.trim();

// Quitar bloques markdown ```html ... ```
if (html.includes('```')) {
  html = html
    .replace(/^```html\s*/i, '')
    .replace(/^```\s*/i, '')
    .replace(/\s*```$/i, '')
    .trim();
}

// Si el HTML no empieza con DOCTYPE, buscar desde donde empieza
if (!html.startsWith('<!DOCTYPE') && !html.startsWith('<!doctype')) {
  const idx = html.search(/<!DOCTYPE/i);
  if (idx > 0) {
    html = html.substring(idx).trim();
  }
}

return [{ json: { html: html } }];
